import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../secretFile.txt";
        String directoryPath = "/var/www/html/uploads/";

        // Normalize the user input to prevent path traversal
        Path sanitizedPath = Paths.get(directoryPath).resolve(Paths.get(userInput).normalize());

        if (!sanitizedPath.startsWith(Paths.get(directoryPath))) {
            System.out.println("Invalid file path");
            return;
        }

        try {
            File file = sanitizedPath.toFile();
            if (file.exists()) {
                byte[] fileContent = Files.readAllBytes(sanitizedPath);
                System.out.println(new String(fileContent));
            } else {
                System.out.println("File not found");
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

